// scripts/build-content-bundle.mjs
//
// Builds content/bundle.json — a single app-consumable projection of the
// authored /content data layer. esbuild bundles JSON natively but not the
// education .md files, so the browser gets one import instead of a directory
// glob. This is a generated artifact (like data/*); never hand-edit it.
//
//   node scripts/build-content-bundle.mjs           # write content/bundle.json
//   node scripts/build-content-bundle.mjs --check    # fail if it would change (CI)

import fs from 'node:fs';
import path from 'node:path';
import crypto from 'node:crypto';
import process from 'node:process';
import { fileURLToPath } from 'node:url';
import { parseFrontmatter } from '../content/schema.mjs';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO = path.join(__dirname, '..');
const CONTENT = path.join(REPO, 'content');
const check = process.argv.includes('--check');

const DOMAINS = ['guidelines', 'trials', 'education', 'calculators', 'references'];

function readDomain(domain) {
  const dir = path.join(CONTENT, domain);
  if (!fs.existsSync(dir)) return [];
  const records = [];
  for (const name of fs.readdirSync(dir).sort()) {
    const file = path.join(dir, name);
    if (name.endsWith('.json')) {
      const data = JSON.parse(fs.readFileSync(file, 'utf8'));
      for (const rec of Array.isArray(data) ? data : [data]) records.push(rec);
    } else if (name.endsWith('.md')) {
      const { data, body } = parseFrontmatter(fs.readFileSync(file, 'utf8'));
      records.push({ ...data, body: body.trim() });
    }
  }
  return records;
}

const domains = {};
for (const d of DOMAINS) domains[d] = readDomain(d);

const payload = {
  guidelines: domains.guidelines,
  trials: domains.trials,
  education: domains.education,
  calculators: domains.calculators,
  references: domains.references,
};

const checksum = 'sha256:' + crypto.createHash('sha256').update(JSON.stringify(payload)).digest('hex').slice(0, 32);
const bundle = {
  _meta: {
    generatedFrom: 'content/{guidelines,trials,education,calculators,references}',
    checksum,
    counts: Object.fromEntries(DOMAINS.map((d) => [d, domains[d].length])),
    note: 'Generated by scripts/build-content-bundle.mjs — do not hand-edit; edit the /content source files.',
  },
  ...payload,
};

const outPath = path.join(CONTENT, 'bundle.json');
const text = JSON.stringify(bundle, null, 2) + '\n';

if (check) {
  let existing = null;
  try { existing = fs.readFileSync(outPath, 'utf8'); } catch { /* new */ }
  if (existing !== text) {
    console.error('build-content-bundle --check: content/bundle.json is stale. Run `npm run content:bundle`.');
    process.exit(1);
  }
  console.log('build-content-bundle --check: bundle is up to date.');
} else {
  fs.writeFileSync(outPath, text, 'utf8');
  console.log(`Wrote content/bundle.json (${Object.entries(bundle._meta.counts).map(([k, v]) => `${k}=${v}`).join(', ')}).`);
}
